28	  async add(record) {
29	    const key = record.id || record.key;
30	    if (this._data.has(key)) throw new Error(`Duplicate key: ${key}`);
31	    this._data.set(key, JSON.parse(JSON.stringify(record)));
32	    return key;
33	  }
