127	export async function assertThrowsAsync(fn, expectedMessage) {
128	  let threw = false, error = null;
129	  try { await fn(); } catch (e) { threw = true; error = e; }
130	  if (!threw) throw new Error(`Expected function to throw${expectedMessage ? ` "${expectedMessage}"` : ''}`);
131	  if (expectedMessage && !error.message.includes(expectedMessage)) {
132	    throw new Error(`Expected error containing "${expectedMessage}", got "${error.message}"`);
133	  }
134	}
